const crypto = require('crypto');

// ── 1. Extract raw body and signature ──────────────────────────────────────
const item = $input.first();
let rawBody;
if (item.binary?.data?.data) {
  rawBody = Buffer.from(item.binary.data.data, 'base64').toString('utf8');
} else if (item.json.rawBody) {
  rawBody = item.json.rawBody;
} else {
  // Fallback: re-serialize parsed body. Caveat: not byte-perfect vs. original bytes.
  // For production with BambooHR (JSON-only webhooks), this is acceptable.
  rawBody = JSON.stringify(item.json.body);
}
const signature = (item.json.headers['x-bamboohr-signature'] || '').trim();
const secret = $env['BAMBOOHR_HMAC_SECRET'];

if (!secret) throw new Error('BAMBOOHR_HMAC_SECRET environment variable not set');
if (!signature) throw new Error('Missing X-BambooHR-Signature header');

// ── 2. Timing-safe HMAC-SHA256 comparison ──────────────────────────────────
const expected = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
let sigValid = false;
try {
  const sigBuf = Buffer.from(signature, 'hex');
  const expBuf = Buffer.from(expected, 'hex');
  sigValid = sigBuf.length === expBuf.length && crypto.timingSafeEqual(sigBuf, expBuf);
} catch (_) { sigValid = false; }
if (!sigValid) throw new Error('HMAC signature verification failed');

// ── 3. Replay protection (fail-closed) ─────────────────────────────────────
const body = item.json.body;
const eventTimeStr = body.eventTime || body.event_time || body.createdAt;
// Reject webhooks with no timestamp — prevents replay bypass via missing field
if (!eventTimeStr) {
  throw new Error('Replay protection: webhook missing eventTime — rejected');
}
const ageMs = Date.now() - new Date(eventTimeStr).getTime();
if (ageMs > 10 * 60 * 1000) {
  throw new Error(`Replay protection: webhook is ${Math.floor(ageMs / 60000)}m old — rejected`);
}

// ── 4. Normalize BambooHR → canonical NewHirePayload ───────────────────────
const employee = body.employee || body;
const firstName = employee.firstName || employee.first_name || employee.preferredName || '';
const lastName  = employee.lastName  || employee.last_name  || '';
const employmentTypeRaw = (employee.employmentStatus || employee.employment_status || employee.employeeType || '').toLowerCase();
const employment_type = employmentTypeRaw.includes('part')
  ? 'PART_TIME'
  : (employmentTypeRaw.includes('contract') || employmentTypeRaw.includes('temp')) ? 'CONTRACTOR' : 'FULL_TIME';

const hire = {
  hire_id: String(employee.id || employee.employeeId || employee.employee_id || ''),
  first_name: firstName,
  last_name: lastName,
  full_name: `${firstName} ${lastName}`.trim(),
  personal_email: employee.personalEmail || employee.personal_email || employee.homeEmail || '',
  job_title: employee.jobTitle || employee.job_title || employee.title || '',
  department: employee.department || employee.departmentName || '',
  employment_type,
  start_date: employee.hireDate || employee.hire_date || employee.startDate || employee.start_date || '',
  manager_email: employee.supervisorEmail || employee.supervisor_email || employee.managerEmail || '',
  location: employee.location || employee.workLocation || employee.homeLocation || 'REMOTE',
  client_slug: $env['CLIENT_SLUG'] || '[CLIENT_SLUG]',
  received_at: new Date().toISOString(),
  source_system: 'bamboohr'
};

// ── 5. Sanitize free-text fields to prevent ILIKE wildcard injection ─────────
// Strip % and _ so job_title/department cannot act as ILIKE wildcards in Workflow 02
const sanitize = (s) => typeof s === 'string' ? s.replace(/[%_]/g, '') : s;
hire.job_title  = sanitize(hire.job_title);
hire.department = sanitize(hire.department);

// ── 6. Validate required fields ─────────────────────────────────────────────
const required = ['hire_id', 'first_name', 'last_name', 'personal_email', 'job_title', 'start_date'];
const missing = required.filter(f => !hire[f]);
if (missing.length > 0) throw new Error(`BambooHR payload missing: ${missing.join(', ')}`);

return [{ json: hire }];

const hire = $('Verify HMAC + Normalize Payload').item.json;
const configRows = $input.all();
if (configRows.length === 0 || !configRows[0].json.slug) {
  throw new Error(`No active company_config found for client_slug: ${hire.client_slug}`);
}
return [{ json: { ...hire, company_config: configRows[0].json } }];

const hire = $('Merge — Hire + Config').item.json;
$execution.customData.set('hire_id', hire.hire_id);
$execution.customData.set('full_name', hire.full_name);
$execution.customData.set('workflow_stage', '01-hris-intake');
return [{ json: hire }];
